column12:
{
  "note": "Alternatives for sriracha sauce in North American stores.",
  "alts": [
    {
      "name_en": "Huy Fong Sriracha",
      "match": "Very close",
      "desc": "The original sriracha sauce, known for its iconic rooster logo.",
      "where": "Condiment aisle"
    },
    {
      "name_en": "Tabasco Sriracha Sauce",
      "match": "Very close",
      "desc": "A spicier take on sriracha with the distinct Tabasco flavor.",
      "where": "Condiment aisle"
    },
    {
      "name_en": "Sky Valley Organic Sriracha",
      "match": "Very close",
      "desc": "An organic version of sriracha with a balanced heat and sweetness.",
      "where": "Organic or condiment aisle"
    },
    {
      "name_en": "Cholula Chili Garlic",
      "match": "Similar",
      "desc": "A different style of hot sauce with garlic notes, less sweet than sriracha.",
      "where": "Condiment aisle"
    }
  ]
}

{
  "note": "Alternatives for butter suitable for lactose intolerance.",
  "alts": [
    {
      "name_en": "Earth Balance Vegan Buttery Sticks",
      "match": "Very close",
      "desc": "Plant-based butter alternative made from oils, completely lactose-free.",
      "where": "Dairy aisle or health food section"
    },
    {
      "name_en": "Miyoko's Creamery European Style Cultured Vegan Butter",
      "match": "Very close",
      "desc": "Lactose-free, plant-based butter with a cultured taste similar to dairy butter.",
      "where": "Dairy aisle or health food section"
    },
    {
      "name_en": "Smart Balance Original Buttery Spread",
      "match": "Similar",
      "desc": "A lactose-free spread made with a blend of oils, designed to taste like butter.",
      "where": "Dairy aisle"
    },
    {
      "name_en": "Coconut Oil",
      "match": "Different but works",
      "desc": "A dairy-free fat that can replace butter in cooking and baking, though flavor differs.",
      "where": "Baking aisle or health food section"
    }
  ]
}

{
  "note": "Alternatives for rice vinegar for those who may not find the original or have dietary restrictions.",
  "alts": [
    {
      "name_en": "Apple Cider Vinegar",
      "match": "Similar",
      "desc": "A fruity vinegar that can substitute rice vinegar in dressings and marinades.",
      "where": "Condiment aisle"
    },
    {
      "name_en": "White Wine Vinegar",
      "match": "Similar",
      "desc": "Offers a mild acidity, suitable for recipes requiring a subtle vinegar flavor.",
      "where": "Condiment aisle"
    },
    {
      "name_en": "Mirin",
      "match": "Different but works",
      "desc": "A sweet Japanese condiment that can mimic rice vinegar's sweetness in dishes.",
      "where": "Asian foods section"
    },
    {
      "name_en": "Seasoned Rice Vinegar (by another brand)",
      "match": "Very close",
      "desc": "Another brand's version of rice vinegar, often found with similar flavor profiles.",
      "where": "Asian foods section"
    }
  ]
}

{
  "note": "Alternatives for chicken breast suitable for vegetarians.",
  "alts": [
    {
      "name_en": "Tofu",
      "match": "Different but works",
      "desc": "A versatile plant-based protein that can be seasoned and cooked similarly to chicken breast.",
      "where": "Refrigerated section, near produce or dairy."
    },
    {
      "name_en": "Seitan",
      "match": "Different but works",
      "desc": "A high-protein meat substitute made from wheat gluten, with a texture similar to chicken.",
      "where": "Refrigerated or dry goods section, often near tofu."
    },
    {
      "name_en": "Tempeh",
      "match": "Different but works",
      "desc": "A fermented soy product that's firm and can be sliced or crumbled like chicken breast.",
      "where": "Refrigerated section, usually near tofu."
    },
    {
      "name_en": "Jackfruit",
      "match": "Different but works",
      "desc": "When young, its texture is similar to shredded chicken, making it a popular meat substitute.",
      "where": "Canned goods aisle or refrigerated section as pre-seasoned options."
    }
  ]
}

{
  "note": "Alternatives for fish sauce catering to Korean taste preferences in North American stores.",
  "alts": [
    {
      "name_en": "Sempio Anchovy Fish Sauce",
      "match": "Very close",
      "desc": "A Korean brand fish sauce made from anchovies, offering a similar flavor profile.",
      "where": "Asian section or international aisle"
    },
    {
      "name_en": "Three Crabs Fish Sauce",
      "match": "Similar",
      "desc": "A Vietnamese fish sauce that's widely available and can substitute in Korean cooking for a umami boost.",
      "where": "Asian section or international aisle"
    },
    {
      "name_en": "Lee Kum Kee Premium Soy Sauce",
      "match": "Different but works",
      "desc": "While not a fish sauce, this soy sauce can provide a salty, umami flavor in a pinch for Korean dishes.",
      "where": "Asian section or condiment aisle"
    },
    {
      "name_en": "Coconut Secret Coconut Aminos",
      "match": "Different but works",
      "desc": "A plant-based alternative that offers a sweet and salty flavor, suitable for those avoiding fish.",
      "where": "Health food section or organic aisle"
    }
  ]
}
